PREFIX : <http://ambrosia.example.org/journalism#>
PREFIX p: <http://ambrosia.example.org/journalism/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE vague {
  full: { SELECT ?name ?specialty ?description ?source WHERE {
  ?experts a :Experts .
  ?documentary a :Documentary .
  ?documentary p:hasExperts ?experts .
  ?archival_footage a :Archival_Footage .
  ?documentary p:hasArchival_Footage ?archival_footage .
  ?experts p:name ?name .
  ?experts p:specialty ?specialty .
  ?archival_footage p:description ?description .
  ?archival_footage p:source ?source .
  ?documentary p:title ?title_f .
  FILTER(STR(?title_f) = "AI Ethics & Society")
} }
  component: { SELECT ?description ?source WHERE {
  ?archival_footage a :Archival_Footage .
  ?documentary a :Documentary .
  ?documentary p:hasArchival_Footage ?archival_footage .
  ?archival_footage p:description ?description .
  ?archival_footage p:source ?source .
  ?documentary p:title ?title_f .
  FILTER(STR(?title_f) = "AI Ethics & Society")
} }
  component_2: { SELECT ?name ?specialty WHERE {
  ?experts a :Experts .
  ?documentary a :Documentary .
  ?documentary p:hasExperts ?experts .
  ?experts p:name ?name .
  ?experts p:specialty ?specialty .
  ?documentary p:title ?title_f .
  FILTER(STR(?title_f) = "AI Ethics & Society")
} }
}

